import React from 'react';

const RateCard = ({ currency, index }) => {
    // Safe number formatting function
    const formatNumber = (num) => {
        // Check if num is a valid number
        if (num === null || num === undefined || num === '') {
            return '0.0000';
        }
        
        // Convert to number if it's a string
        const number = typeof num === 'string' ? parseFloat(num) : num;
        
        // Check if it's a valid number
        if (isNaN(number)) {
            return '0.0000';
        }
        
        return number.toFixed(4);
    };

    // Safe access to currency properties with defaults
    const currencyName = currency?.name || 'Unknown';
    const currencyCode = currency?.code || 'N/A';
    const currencyIcon = currency?.icon || 'fa-money-bill-wave';
    const sellRate = currency?.sell_rate;
    const buyRate = currency?.buy_rate;
    
    // Calculate spread if both rates exist
    const spread = (sellRate && buyRate) ? 
        (parseFloat(buyRate) - parseFloat(sellRate)).toFixed(4) : '0.0000';

    return (
        <div className="rate-card" style={{ animationDelay: `${(index || 0) * 0.05}s` }}>
            <div className="rate-card-header">
                <div className="currency-icon">
                    <i className={`fas ${currencyIcon}`}></i>
                </div>
                <div className="currency-info">
                    <div className="currency-name">{currencyName}</div>
                    <div className="currency-code">{currencyCode}</div>
                </div>
                <div className="trend-icon">
                    <i className="fas fa-chart-line"></i>
                </div>
            </div>
            
            <div className="rate-card-body">
                <div className="rate-item">
                    <div className="rate-label">
                        <i className="fas fa-arrow-up"></i> SELLING
                    </div>
                    <div className="rate-value sell-rate">
                        {formatNumber(sellRate)}
                    </div>
                </div>
                <div className="rate-divider"></div>
                <div className="rate-item">
                    <div className="rate-label">
                        <i className="fas fa-arrow-down"></i> BUYING
                    </div>
                    <div className="rate-value buy-rate">
                        {formatNumber(buyRate)}
                    </div>
                </div>
            </div>
            
            <div className="rate-card-footer">
                <span>ETB per unit</span>
                <span className="spread-info">
                    <i className="fas fa-chart-simple"></i> Spread: {spread}
                </span>
            </div>
        </div>
    );
};

export default RateCard;
